  #include <TFT_eSPI.h>
  #include "f1_logo.h"

  TFT_eSPI tft = TFT_eSPI();

  void setup() {
    tft.init();
    tft.setRotation(1);
    tft.fillScreen(TFT_WHITE);

    // Centre the logo on the 128x64 screen
    int x = (tft.width()  - F1_LOGO_WIDTH)  / 2;
    int y = (tft.height() - F1_LOGO_HEIGHT) / 2;

    tft.pushImage(x, y, F1_LOGO_WIDTH, F1_LOGO_HEIGHT, f1_logo);
  }

